            color: { type: "colormap", default: "Blues", steps: 3, mode: "singlehue" },
            threshold: { type: "advanced_slider", breaks: [0.33, 0.66] },
            connect: true,
            cell: 64,
            solid_px: 15,
            boundary_px: 2
